+      panel.hidden = panel.dataset.tabPanel !== tabId;
+    }
+    localStorage.setItem(storageKey, tabId);
+    onLogsActiveChange(tabId === "logs");
+    onProcessesActiveChange(tabId === "processes");
+  };
